/* DilAvatar — foto-kare tabanlı konuşan asistan (gerçek resim, gerçek ağız/göz hareketi).
   4 kare: rest (ağız kapalı), half (hafif açık), open (tam açık), blink (göz kapalı).
   Konuşurken kareler arası geçer; göz kırpınca blink karesi gösterilir.
   API: mount, setMouth, speakText, thinking, stop, blink, setGender(stub), getGender
*/
(function (global) {
  "use strict";
  var FR = {
    rest:  "data:image/jpeg;base64,",
    half:  "data:image/jpeg;base64,",
    open:  "data:image/jpeg;base64,",
    blink: "data:image/jpeg;base64,"
  };
  var state = { faceEl:null, imgEl:null, cur:"rest", isBlinking:false, speakTimer:null, blinkTimer:null, blinkOffTimer:null, thinkTimer:null, speaking:false, thinking:false };

  function show(frame){
    if(frame==="round"||frame==="wide") frame="half";
    if(frame==="closed") frame="rest";
    if(frame==="teeth"||frame==="open") frame="open";
    if(!FR[frame]) frame="rest";
    state.cur=frame;
    if(state.imgEl && !state.isBlinking) state.imgEl.src = FR[frame];
  }
  function clearSpeak(){ if(state.speakTimer){clearTimeout(state.speakTimer);state.speakTimer=null;} }
  function clearThink(){ if(state.thinkTimer){clearInterval(state.thinkTimer);state.thinkTimer=null;} }

  // Türkçe harf -> kare
  function frameForChar(ch){
    ch=String(ch||"").toLocaleLowerCase("tr-TR");
    if("aeâo".indexOf(ch)>=0) return "open";   // geniş açık sesliler
    if("uıiüöy".indexOf(ch)>=0) return "half"; // dar sesliler: hafif açık
    if("mbp".indexOf(ch)>=0) return "rest";    // dudak kapanır
    if(/\s/.test(ch)) return "rest";
    return "half";                              // ünsüzler: hafif kıpırtı
  }

  function blinkOnce(){
    if(!state.imgEl) return;
    if(state.blinkOffTimer) clearTimeout(state.blinkOffTimer);
    state.isBlinking = true;
    state.imgEl.src = FR.blink;
    state.blinkOffTimer = setTimeout(function(){
      state.isBlinking = false;
      state.imgEl.src = FR[state.cur] || FR.rest;
    }, 140);
  }
  function scheduleBlink(){
    if(state.blinkTimer) clearTimeout(state.blinkTimer);
    var next = 2600 + Math.random()*2600;
    state.blinkTimer = setTimeout(function(){ blinkOnce(); scheduleBlink(); }, next);
  }

  var API = {
    mount: function(elId){
      var host = (typeof elId==="string") ? document.getElementById(elId) : elId;
      if(!host) return;
      host.innerHTML =
        '<div class="dilav-wrap" style="display:flex;flex-direction:column;align-items:center;gap:8px">'+
          '<div class="dilav-face" style="position:relative;width:100%;max-width:220px;aspect-ratio:1;border-radius:50%;overflow:hidden;border:3px solid #b59867;box-shadow:0 12px 34px rgba(0,0,0,.4);background:#0b1120">'+
            '<img class="dilav-img" alt="asistan" src="'+FR.rest+'" style="width:100%;height:100%;object-fit:cover;display:block"/>'+
          '</div>'+
        '</div>';
      state.faceEl = host.querySelector(".dilav-face");
      state.imgEl = host.querySelector(".dilav-img");
      show("rest");
      scheduleBlink();
    },
    setMouth: function(shape){ show(shape||"rest"); },
    speakText: function(text, durationMs){
      this.stop();
      text=String(text||"");
      var chars=Array.prototype.slice.call(text);
      if(!chars.length){ show("rest"); return; }
      state.speaking=true;
      var total=Number(durationMs);
      var per = (total&&isFinite(total)) ? total/chars.length : 110;
      per = Math.max(70, Math.min(150, per));
      var i=0;
      function step(){
        if(i>=chars.length){ show("rest"); state.speaking=false; state.speakTimer=null; return; }
        show(frameForChar(chars[i])); i++;
        state.speakTimer=setTimeout(step, per);
      }
      step();
    },
    thinking: function(on){
      state.thinking=!!on; clearThink();
      if(!on){ show("rest"); return; }
      var flip=false;
      state.thinkTimer=setInterval(function(){ flip=!flip; show(flip?"half":"rest"); }, 520);
    },
    blink: blinkOnce,
    stop: function(){ clearSpeak(); clearThink(); state.speaking=false; state.thinking=false; show("rest"); },
    setGender: function(){}, getGender: function(){ return "erkek"; }
  };
  global.DilAvatar = API;
})(window);
